# Worked focus: http-py-latency-throughput-budget — Measure latency distributions, queue time, throughput, error rate, and saturation against an end-to-end service objective. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_performance_release_defense_5(p95_ms: int, latency_budget_ms: int, queue_depth: int, queue_capacity: int) -> dict[str, bool]:
    assert all(isinstance(value, int) for value in (p95_ms, latency_budget_ms, queue_depth, queue_capacity))
    if p95_ms < 0 or latency_budget_ms <= 0 or queue_depth < 0 or queue_capacity <= 0:
        return {"release": False, "saturated": True}
    saturated = queue_depth >= queue_capacity
    return {"release": p95_ms <= latency_budget_ms and not saturated, "saturated": saturated}

